from devforge.executors.adapters import BaseExecutorAdapter

class MyToolAdapter(BaseExecutorAdapter):
    def __init__(self):
        super().__init__('my_tool', ('implementation',), ('software_engineer',))
    def _build_cli_argv(self, request): return ['my-tool', '--task', request['goal']]

dispatch = adapter.dispatch(work_package, runtime_context)
if dispatch.accepted:
    print(f'Dispatched {dispatch.execution_id}')
